const CONFIG = {
  sensitivity: 80,
  elasticity: 0.08,
  friction: 0.88,
  palette: 'tokyoPurple',
}

function color(p) {
  const t = p.br / 255
  if (CONFIG.palette === 'matrix') return `rgb(0,${Math.round(80 + t * 175)},0)`
  if (CONFIG.palette === 'sampled') return `rgb(${p.r},${p.g},${p.b})`
  if (CONFIG.palette === 'tokyoPurple') return `rgb(${Math.round(70 + t * 117)},${Math.round(55 + t * 99)},${Math.round(110 + t * 137)})`
  return `rgb(${Math.round(20 + t * 80)},${Math.round(80 + t * 175)},${Math.round(70 + t * 148)})`
}

export default function AsciiParticles({ style }) {
  const canvasRef = useRef(null)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return
    const dpr = window.devicePixelRatio || 1
    const W = canvas.offsetWidth, H = canvas.offsetHeight
    canvas.width = W * dpr; canvas.height = H * dpr
    ctx.scale(dpr, dpr)

    const n = PARTICLES.length
    const px = new Float32Array(n), py = new Float32Array(n)
    const vx = new Float32Array(n), vy = new Float32Array(n)
    const tx = new Float32Array(n), ty = new Float32Array(n)
    const chars = PARTICLES.map(p => p.c)
    const colors = PARTICLES.map(color)

    let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity
    for (let i = 0; i < n; i++) {
      const x = PARTICLES[i].ox
      const y = PARTICLES[i].oy
      if (x < minX) minX = x
      if (x > maxX) maxX = x
      if (y < minY) minY = y
      if (y > maxY) maxY = y
    }

    const sourceW = Math.max(1, maxX - minX)
    const sourceH = Math.max(1, maxY - minY)
    const padding = 10
    const scale = Math.min((W - padding * 2) / sourceW, (H - padding * 2) / sourceH)
    const offsetX = (W - sourceW * scale) / 2 - minX * scale
    const offsetY = (H - sourceH * scale) / 2 - minY * scale

    for (let i = 0; i < n; i++) {
      tx[i] = PARTICLES[i].ox * scale + offsetX
      ty[i] = PARTICLES[i].oy * scale + offsetY
    }

    for (let i = 0; i < n; i++) {
      px[i] = Math.random() * W; py[i] = Math.random() * H
    }

    const mouse = { x: -9999, y: -9999 }
    const handleMouseMove = (e) => {
      const r = canvas.getBoundingClientRect()
      mouse.x = e.clientX - r.left
      mouse.y = e.clientY - r.top
    }
    const handleMouseLeave = () => { mouse.x = -9999; mouse.y = -9999 }
    canvas.addEventListener('mousemove', handleMouseMove)
    canvas.addEventListener('mouseleave', handleMouseLeave)

    let raf
    function loop() {
      ctx.clearRect(0, 0, W, H)
      ctx.font = `${Math.max(6, 11 * scale)}px Courier New`
      ctx.textBaseline = 'middle'
      const r2 = CONFIG.sensitivity ** 2
      for (let i = 0; i < n; i++) {
        const dx = mouse.x - px[i], dy = mouse.y - py[i], d2 = dx*dx+dy*dy
        if (d2 < r2 && d2 > 0.01) {
          const d = Math.sqrt(d2), f = (CONFIG.sensitivity - d) / CONFIG.sensitivity
          vx[i] -= dx/d*f*8; vy[i] -= dy/d*f*8
        }
        vx[i] += (tx[i] - px[i]) * CONFIG.elasticity
        vy[i] += (ty[i] - py[i]) * CONFIG.elasticity
        vx[i] *= CONFIG.friction; vy[i] *= CONFIG.friction
        px[i] += vx[i]; py[i] += vy[i]
        ctx.fillStyle = colors[i]
        ctx.fillText(chars[i], px[i], py[i])
      }
      raf = requestAnimationFrame(loop)
    }
    loop()
    return () => {
      cancelAnimationFrame(raf)
      canvas.removeEventListener('mousemove', handleMouseMove)
      canvas.removeEventListener('mouseleave', handleMouseLeave)
    }
  }, [])

  return <canvas ref={canvasRef} style={{ display: 'block', width: '100%', height: '100%', ...style }} />
}
